PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?coach WHERE {
  wd:Q79800 wdt:P10449 | wdt:P5393 | wdt:P6087 | p:P5124 / ps:P5124 ?coach .
  OPTIONAL {
    ?coach wdt:P106 wd:Q136661790
  }
  .
  FILTER(REGEX(STR(?coach) , '^http://www.wikidata.org/entity/Q'))
}
LIMIT 1
